  ('TN001', 'CAT_HEADPHONE', 'SonicBuds Air Lite', 'Tai nghe TWS nho gon, Bluetooth 5.3, thoi luong pin 24 gio kem hop sac, mau trang.', 'https://cdnv2.tgdd.vn/mwg-static/tgdd/Products/Images/54/342638/tai-nghe-bluetooth-true-wireless-oppo-enco-buds-3-eteg1-trang-1-638935504170479935-750x500.jpg', 990000.00, 10, 120, 4.33, 512),
